# -*- coding: utf-8 -*-

n, m, x, y, z, p = map(int, input().split())

def rotate90(x, y):
    return y, n-x+1

def rotate90_clockwise(x, y):
    return n-y+1, x

def rotate90_counterclockwise(x, y):
    return y, m-x+1

for _ in range(p):
    x1, y1 = map(int, input().split())
    for _ in range(x):
        x1, y1 = rotate90(x1, y1)
    for _ in range(y):
        x1, y1 = rotate90_clockwise(x1, y1)
    for _ in range(z):
        x1, y1 = rotate90_counterclockwise(x1, y1)
    print(x1, y1)
